pub mod inspector;
pub mod utils;

pub use inspector::{
    AsyncPrecompileInspector, BasicAsyncCallResult, AUDIO_CALL_PRECOMPILE, DKMS_KEY_PRECOMPILE,
    FHE_PRECOMPILE, HTTP_CALL_PRECOMPILE, IMAGE_CALL_PRECOMPILE, LLM_CALL_PRECOMPILE,
    LONG_RUNNING_HTTP_PRECOMPILE, PERSISTENT_AGENT_PRECOMPILE, SOVEREIGN_AGENT_PRECOMPILE,
    VIDEO_CALL_PRECOMPILE, ZK_TWO_PHASE_PRECOMPILE,
};

pub const DEFAULT_MAX_TTL_BLOCKS: u64 = 500;

pub fn max_ttl_blocks() -> u64 {
    use std::sync::OnceLock;
    static MAX_TTL: OnceLock<u64> = OnceLock::new();
    *MAX_TTL.get_or_init(|| {
        std::env::var("ASYNC_MAX_TTL_BLOCKS")
            .ok()
            .and_then(|s| s.parse().ok())
            .unwrap_or(DEFAULT_MAX_TTL_BLOCKS)
    })
}

pub const MAX_TTL_BLOCKS: u64 = DEFAULT_MAX_TTL_BLOCKS;
pub const MAX_PHASE2_DEADLINE_OFFSET: u64 = 70_000;
